import{_ as e,o as a,c as l,a7 as r}from"./chunks/framework.C5lS51Lu.js";const c=JSON.parse('{"title":"目录","description":"","frontmatter":{},"headers":[],"relativePath":"md/life/gourmet-food/01.早餐特辑/01.豆浆.md","filePath":"md/life/gourmet-food/01.早餐特辑/01.豆浆.md"}'),i={name:"md/life/gourmet-food/01.早餐特辑/01.豆浆.md"};function d(n,t,h,o,s,f){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to “目录”">​</a></h1><p>[toc]</p><hr><h1 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to “说明”">​</a></h1><hr><h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to “介绍”">​</a></h1><p>豆浆（Soybean Milk），中国汉族传统饮品，最早的豆浆为西汉淮南王刘安制作。将大豆用水泡涨后磨碎、过滤、煮沸而成。豆浆营养非常丰富，且易于消化吸收。与西方的牛奶不同，豆浆是非常具有中国民族特色的食品，广泛流行于华人地区。</p><p>在欧美享有“植物奶”的美誉。豆浆含有丰富的植物蛋白和磷脂，还含有维生素B1、B2和烟酸。此外，豆浆还含有铁、钙等矿物质，尤其是其所含的钙，非常适合于各种人群，包括老人、成年人、青少年、儿童等等。</p><p>鲜豆浆四季都可饮用。春秋饮豆浆，滋阴润燥，调和阴阳；夏饮豆浆，消热防暑，生津解渴；冬饮豆浆，祛寒暖胃，滋养进补。其实，除了传统的黄豆浆外，豆浆还有很多花样，红枣、枸杞、绿豆、百合等都可以成为豆浆的配料。</p><hr><h1 id="原料" tabindex="-1">原料 <a class="header-anchor" href="#原料" aria-label="Permalink to “原料”">​</a></h1><p>制作原料配比</p><table tabindex="0"><thead><tr><th style="text-align:left;">原料</th><th style="text-align:left;">计量1</th><th style="text-align:left;">计量2</th><th style="text-align:left;">计量3</th></tr></thead><tbody><tr><td style="text-align:left;">凉水</td><td style="text-align:left;">8.3L</td><td style="text-align:left;">16.6L</td><td style="text-align:left;">24.9L</td></tr><tr><td style="text-align:left;">黄豆（大豆）</td><td style="text-align:left;">1斤、0.5kg</td><td style="text-align:left;">2斤、1kg</td><td style="text-align:left;">3斤、1.5kg</td></tr><tr><td style="text-align:left;">白糖</td><td style="text-align:left;">1斤、0.5kg</td><td style="text-align:left;">2斤、1kg</td><td style="text-align:left;">3斤、1.5kg</td></tr></tbody></table><hr><h1 id="制法" tabindex="-1">制法 <a class="header-anchor" href="#制法" aria-label="Permalink to “制法”">​</a></h1><h2 id="步骤一" tabindex="-1">步骤一 <a class="header-anchor" href="#步骤一" aria-label="Permalink to “步骤一”">​</a></h2><p>淘洗干净，加入清水，浸泡10个小时以上。</p><p>时间安排上，可以在当天下午两三点的时候泡上，第二天凌晨五点的时候，就可以开始<a href="#步骤二">步骤二</a>操作，磨豆浆。</p><h2 id="步骤二" tabindex="-1">步骤二 <a class="header-anchor" href="#步骤二" aria-label="Permalink to “步骤二”">​</a></h2><ol><li><p>将泡好的黄豆导入机器中</p></li><li><p>计算好的白糖导入机器</p></li><li><p>一般购买的豆浆机内壁都有刻度，可按照刻度加水</p></li><li><p>启动机器开始工作</p></li></ol><hr>',21)])])}const x=e(i,[["render",d]]);export{c as __pageData,x as default};
